import './StepperStep.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import { Divider } from '../../Divider';
import { Icon } from '../../Icon';
import { Typography } from '../../Typography';
import { ICON_STATE_MAP, ORDER_STATE_MAP, STEP_ICON_MAP } from '../common/constants';
import type { StepCommonProps } from '../common/step.types';

export const StepperStep: FC<StepCommonProps> = ({
	id,
	signature,
	label,
	state = 'non-visited',
	activated = false,
	order,
	onClick,
	direction,
}) => {
	const handleClick = (): void => {
		onClick?.(id);
	};

	return (
		<div
			className={classNames('dsb_step', `dsb_step__${state}`, state !== 'disabled' && onClick && 'dsb_step__clickable')}
			onClick={handleClick}
			onKeyDown={event => event.key === 'Enter' && handleClick()}
			role={state !== 'disabled' && onClick ? 'button' : 'presentation'}
			tabIndex={state !== 'disabled' && onClick ? 0 : -1}
		>
			<div className={`dsb_step-content dsb_step-content__${direction}`}>
				{direction === 'vertical' && (
					<Divider
						className={classNames(
							'dsb_step-border',
							'dsb_step-border__vertical',
							activated && 'dsb_step-border__activated',
						)}
					/>
				)}
				{ORDER_STATE_MAP[state] && (
					<span className={classNames('dsb_step-order', `dsb_step-order__${state}`)}>
						<Typography variant="body2" className="dsb_step-order-number">
							{order}
						</Typography>
					</span>
				)}
				{ICON_STATE_MAP[state] && (
					<Icon
						size="large"
						iconName={STEP_ICON_MAP[state]}
						className={classNames('dsb_step-icon', `dsb_step-icon__${state}`)}
					/>
				)}
				<div className={classNames('dsb_step-body')}>
					{signature && (
						<Typography variant="caption" className={classNames('dsb_step-body-text', `dsb_step-body-text__${state}`)}>
							{signature}
						</Typography>
					)}
					<Typography
						variant="body2"
						className={classNames('dsb_step-body-main-text', `dsb_step-body-main-text__${state}`)}
					>
						{label}
					</Typography>
				</div>
			</div>
			{direction === 'horizontal' && (
				<Divider
					className={classNames(
						'dsb_step-border',
						'dsb_step-border__horizontal',
						activated && 'dsb_step-border__activated',
					)}
				/>
			)}
		</div>
	);
};
